using Financeiro.Domain.Entities; using Microsoft.EntityFrameworkCore;
namespace Financeiro.Infrastructure.Persistence; public class AppDbContext : DbContext { public AppDbContext(DbContextOptions<AppDbContext> options):base(options){} public DbSet<Usuario> Usuarios => Set<Usuario>(); public DbSet<PeriodoPagamento> PeriodosPagamento => Set<PeriodoPagamento>(); public DbSet<DespesaPeriodo> DespesasPeriodo => Set<DespesaPeriodo>(); protected override void OnModelCreating(ModelBuilder modelBuilder){ modelBuilder.ApplyConfigurationsFromAssembly(typeof(AppDbContext).Assembly); base.OnModelCreating(modelBuilder);} }
